6 TCGA-OV bulk expression
The bulk expression input is open TCGA-OV primary tumor expression. The notebook uses TCGAbiolinks to obtain HTSeq counts from GDC and then keeps a small, deterministic subset for smoke testing or reduced local rendering.

tcga_cache &lt;- file.path("data/cache", paste0("tcga_ov_bulk_", n_tcga_samples, ".rds"))

if (file.exists(tcga_cache)) {
  bulk_expr &lt;- readRDS(tcga_cache)
} else {
  if (!requireNamespace("TCGAbiolinks", quietly = TRUE) ||
      !requireNamespace("SummarizedExperiment", quietly = TRUE)) {
    stop("Install TCGAbiolinks and SummarizedExperiment to download TCGA-OV bulk expression.")
  }

  query &lt;- query_tcga_ov_counts(n_tcga_samples, seed = params$seed)
  TCGAbiolinks::GDCdownload(query, directory = "data/raw/TCGA_OV")
  se &lt;- TCGAbiolinks::GDCprepare(query, directory = "data/raw/TCGA_OV")

  counts &lt;- SummarizedExperiment::assay(se)
  rd &lt;- as.data.frame(SummarizedExperiment::rowData(se))
  gene_symbols &lt;- rd$external_gene_name %||% rd$gene_name %||% rd$gene_id
  keep &lt;- !is.na(gene_symbols) & gene_symbols != ""
  counts &lt;- counts[keep, , drop = FALSE]
  gene_symbols &lt;- gene_symbols[keep]

  counts_by_symbol &lt;- rowsum(as.matrix(counts), group = gene_symbols)
  bulk_expr &lt;- normalize_bulk_matrix(counts_by_symbol)

  saveRDS(bulk_expr, tcga_cache)
}

